def _material_slots_val(v: object) -> dict[str, str | None] | None:
    if v in (None, ""):
        return None
    if not isinstance(v, dict):
        raise ValueError("materialSlots must be a JSON object or empty")
    out: dict[str, str | None] = {}
    for raw_key, raw_value in v.items():
