/** UI workbench presets — shared types for layouts and discipline perspectives */

export type WorkspaceLayoutPreset =
  | 'classic'
  /** Plan + orthographic 3D side-by-side */
  | 'split_plan_3d'
  /** Plan with section/elevation placeholder pane */
  | 'split_plan_section'
  /** Emphasizes issues/advisor/coord reads */
  | 'coordination'
  /** Room schedule beside plan */
  | 'schedules_focus'
  /** Schema summary + validation context for agents */
  | 'agent_review';

/** Discipline filter for Advisor and future toolbars — matches server violation tagging when present */
export type PerspectiveId =
  | 'architecture'
  | 'structure'
  | 'mep'
  | 'coordination'
  | 'construction'
  /** Show all advisory rows */
  | 'agent';
import type { PerspectiveId, Violation } from '@bim-ai/core';

function disc(v: Violation): string {
  return (v.discipline ?? 'general').toLowerCase();
}

/** Perspective-based advisory filter — backend tags discipline when available */
export function filterViolationsForPerspective(rows: Violation[], pid: PerspectiveId): Violation[] {
  if (pid === 'agent') return rows;

  return rows.filter((v) => {
    const d = disc(v);

    switch (pid) {
      case 'architecture':
        return d === 'general' || d === 'architecture';

      case 'structure':
        return d === 'general' || d === 'structure';

      case 'mep':
        return d === 'general' || d === 'mep';

      case 'construction':
        return d === 'general' || d === 'construction';

      case 'coordination':
        return d === 'general' || d === 'coordination' || v.severity === 'error';

      default:
        return true;
    }
  });
}

